class Solution {
    public long repairCars(int[] ranks, int cars) {
        long left = 0, right = (long) 1e14;
        while (left < right) {
            long mid = left + (right - left) / 2;
            long count = 0;
            for (int rank : ranks) {
                count += (long) Math.sqrt(mid / rank);
            }
            if (count >= cars) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }
}
